const Q_GOVERNMENT_2009=[{"id": "objective>Government>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Inspector General of Police is appointed by the executive on the advice of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Police Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Police Service Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">House of Representatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Senate of the Federal Republic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Inspector General of Police in Nigeria is appointed by the President on the advice of the Nigerian Police Council. The Nigerian Police Council is a constitutional body that advises the President on the administration of the Nigeria Police Force. It is composed of the President as the chairman, the Inspector General of Police, the Chairman of the Police Service Commission, and the Governors of each of the states of the Federation.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major problem associated with the Nigerian federalism is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethnic conflicts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boundary disputes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fiscal allocation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major problem associated with the Nigerian federalism is fiscal allocation. Fiscal allocation refers to the distribution of resources among the different levels of government. In Nigeria, there have been persistent issues with the allocation of resources, with many states and local governments claiming that the federal government retains a disproportionate share of the country's wealth. This has led to conflicts and calls for a review of the revenue allocation formula.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM"}, {"id": "objective>Government>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The six African members of the Nigerian Council were nominated by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Queen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">district officer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">governor</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The six African members of the Nigerian Council were nominated by the Governor. The Nigerian Council was a legislative body established by the British colonial authorities in Nigeria. The Governor, who was the representative of the British Crown, had the power to nominate members to the council.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : OLIVER LYTTLETON CONSTITUTION 1954"}, {"id": "objective>Government>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Second Republic, the total membership of each House of Assembly was determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electoral commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electorate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Second Republic, the total membership of each House of Assembly was determined by the Constitution. The Constitution of a country is the supreme law of the land and it stipulates the structure and operation of the government, including the composition of the legislative houses.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : SECOND REPUBLIC"}, {"id": "objective>Government>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization and commercialization programmes in Nigeria have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased public utilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de-emphasised government ownership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced government revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraged corruption</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization and commercialization programmes in Nigeria have de-emphasised government ownership. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The government ceases to be the owner of the entity or business. Commercialization is the management or running of an entity in such a way as to make it profitable. It involves the restructuring of a public enterprise to operate as a profit-making commercial entity. Both processes reduce the role of government in controlling and managing the economy.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fear of domination in the public service led to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adoption of population as a formula for revenue allocation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of the Civil Service Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduction of rational presidency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment  of the Federal Character Commission</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fear of domination in the public service led to the establishment of the Federal Character Commission. The Federal Character Commission is a Nigerian quasi-federal government body, established to promote, monitor and enforce compliance with the principles of the proportional sharing of all bureaucratic, economic, media and political posts at all levels of government. It was created to prevent the domination of ethnic groups in public service and to ensure equal representation of all states or ethnic groups.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Igbo political system, the most senior member of the council of elders is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">okpara</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eze</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ofo</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Igbo political system, the most senior member of the council of elders is the 'ofo'. The 'ofo' is a symbol of authority and leadership in the Igbo traditional political system. It is held by the most senior member of the council of elders, who is seen as the custodian of the community's customs and traditions.</div>", "topic": "PRE-COLONIAL POLITICS : IGBO PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The immediate cause of the 1966 military coup de'etat in Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nepotism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political instability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">military ambition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corruption</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The immediate cause of the 1966 military coup d'etat in Nigeria was 'political instability'. The period leading up to the coup was marked by a high level of political instability characterized by violence, rigging of elections, and ethnic tensions. While issues like corruption, nepotism, and military ambition were also present, they were underlying causes. The immediate trigger was the unstable political environment.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : FACTORS THAT LED TO MILITARY INTERVENTION"}, {"id": "objective>Government>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The exclusive list is reserved for legislation by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">regional government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">state government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">local government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The exclusive list in a federal system of government is a list of items on which only the federal government can make laws. The items on this list are usually issues of national importance or those that require a uniform system across the country. Therefore, the exclusive list is reserved for legislation by the federal government.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The participation of Nigeria in the Second World War created in the nationalists the awareness that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Africans were superior</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Africans were more qualified to rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Europeans were not superior</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Europeans were less tactful in warfare</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The participation of Nigeria in the Second World War helped to create an awareness among the nationalists that the Europeans were not superior. This is because they saw that the Europeans also suffered and struggled in the war, just like any other human beings. This realization helped to fuel the desire for independence among the nationalists.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALISM – MEANING, TYPES"}, {"id": "objective>Government>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following mostly militates against the efficiency and productivity of public corporations in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Incessant interference by government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The management teams are always appointed at will</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boards are often non-professionals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">members of the management team are always at loggerheads</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency and productivity of public corporations in Nigeria are mostly militated against by incessant interference by the government. This is because the government, as the major stakeholder, often interferes in the operations of these corporations, thereby affecting their efficiency and productivity. The other options may also affect the efficiency and productivity of public corporations but not as much as government interference.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : PROBLEMS"}, {"id": "objective>Government>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The power to nominate members of the judiciary at the federal level under the 1999 Constitution is vested in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Federal Judicial Service Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supreme Court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Judicial Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Bar association</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The power to nominate members of the judiciary at the federal level under the 1999 Constitution is vested in the National Judicial Council. The National Judicial Council is a body established by the Constitution of the Federal Republic of Nigeria to protect the Judiciary's independence. It is responsible for the appointment, promotion, and discipline of judicial officers. The Federal Judicial Service Commission is responsible for advising the National Judicial Council on suitable candidates for nomination to the judiciary. The Supreme Court and the Nigerian Bar Association do not have the power to nominate members of the judiciary.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prior to 1976, the local government system practised in Northern Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chief-and-council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chief-in-council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prefectorial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">council</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prior to 1976, the local government system practiced in Northern Nigeria was the 'Chief-in-Council' system. This system was characterized by a traditional ruler (the Chief) who made decisions in consultation with a council of elders or notable individuals within the community.</div>", "topic": "LOCAL GOVERNMENT"}, {"id": "objective>Government>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the segemented Tiv society, governance was usually confined to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">age grade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chiefdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">family</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clan</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the segmented Tiv society, governance was usually confined to the 'clan'. The Tiv society is traditionally a highly decentralized society with no centralized authority. Instead, authority and governance are distributed among various clans, each of which is autonomous and self-governing.</div>", "topic": "PRE-COLONIAL POLITICS"}, {"id": "objective>Government>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following influenced nationalist activities in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Indian Congress Party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Negro Diaspora Congress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pan-africa Congress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Congress of British West Africa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Pan-African Congress influenced nationalist activities in Nigeria. The Pan-African Congress was a series of meetings that focused on addressing the issues facing Africa as a result of European colonization. The congresses, held from 1900 to 1945, were significant in the sense that they connected people of African descent from around the globe, and they were a key factor in the push for decolonization and independence of African countries, including Nigeria.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALIST MOVEMENTS – EMERGENCE, GOALS, STRATEGIES"}, {"id": "objective>Government>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The party that did not control any state in the Second Republic was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NAP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PRB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NPP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GNPP</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The People's Redemption Party (PRP) did not control any state in the Second Republic. The Second Republic in Nigeria was a period of democratic rule from 1979 to 1983. During this time, several political parties were formed, and they competed for control of the states. However, the PRP was not able to secure control of any state.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : SECOND REPUBLIC"}, {"id": "objective>Government>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'Pacification' refers to a process through which some areas in Nigeria were acquired by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">military conquest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gunboat diplomacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">signing of treaties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peaceful negotiation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">'Pacification' refers to the process of subduing a particular area or region through force, often in the context of colonialism. In the case of Nigeria, this was done through military conquest. The British used military force to subdue and control various regions of Nigeria, particularly in the late 19th and early 20th centuries. This process is often referred to as 'pacification'.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH PROCESS OF ACQUISITION – TRADE, MISSIONARY ACTIVITIES, COMPANY RULE, CROWN COLONY, PROTECTORATE"}, {"id": "objective>Government>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Counter-trade was introduced by the government led by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abdulsalami Abubakar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Olusegun Obasanjo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muhammadu Buhari</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibrahim Babangida</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Counter-trade is a form of international trade in which goods or services are exchanged for other goods or services rather than for hard currency. This type of trade is often used when hard currency is difficult to obtain or when countries want to bypass foreign exchange controls. In Nigeria, counter-trade was introduced during the regime of General Ibrahim Babangida in the 1980s as a response to the economic crisis and foreign debt.</div>", "topic": "ECONOMIC POLICIES AND DEVELOPMENT STRATEGIES : COUNTER-TRADE"}, {"id": "objective>Government>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major limitation of the Commonwealth is that it lacks</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the power to set formula rules to govern the affairs of member-nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an organizational structure and a definite identity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enough funds to run its affairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the power to compel member-nations to comply with its decisions</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Commonwealth operates on a consensus model, meaning that decisions are made collectively and member nations are not compelled to follow them. Therefore, it lacks the power to compel member-nations to comply with its decisions.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : COMMONWEALTH"}, {"id": "objective>Government>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries has withdrawn her membership from ECOWAS</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Senegal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea Bissau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Burkina Faso</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania withdrew from ECOWAS in 2000. The question is self explanatory in relation to the answer.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS"}, {"id": "objective>Government>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a major threat to OPEC?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Persistence of war in the Middle East</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The discovery of crude oil in more countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Antagonism by the major world powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development of valuable alternative to crude oil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Organization of the Petroleum Exporting Countries (OPEC) is a group of oil-producing nations that aim to ensure a steady income to the member states and to secure reliable supply of oil to the consumers. The development of valuable alternatives to crude oil is a major threat to OPEC because it could reduce the global demand for oil, thereby affecting the income of the member states. This is because alternatives to crude oil such as renewable energy sources (solar, wind, etc.) are becoming more popular due to environmental concerns and technological advancements.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OPEC"}, {"id": "objective>Government>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The AU's right to intervene in a member country in crisis portrays it as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an international organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a regional organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a supranational organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a continental organization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The African Union (AU) is a supranational organization. A supranational organization is a type of multinational political union where negotiated power is delegated to an authority by governments of member states. The term is sometimes used to describe the European Union (EU), as a new type of political entity. The AU's right to intervene in a member country in crisis portrays it as a supranational organization because it has the power to make decisions and take actions that could override the sovereignty of its member countries in certain situations.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : AU"}, {"id": "objective>Government>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The permanent membership of the UN Security Council is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ten</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fifteen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eleven</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The United Nations Security Council is composed of 15 members, but only five of them are permanent. These five are China, France, Russia, the United Kingdom, and the United States. These countries were the main allies in World War II and have maintained the world's most powerful economies since then.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of flexible constitution is that it allows for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political awareness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constitutional stability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction of ambiguities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ease of amendment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A flexible constitution is one that can be easily amended or changed. This is an advantage because it allows for the constitution to adapt to changing circumstances and needs. It can be updated to reflect societal changes, technological advancements, or shifts in political climate. This flexibility can help to prevent constitutional crises and maintain the relevance and effectiveness of the constitution.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Power refers to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ability to impose one's will upon others</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal nature off a constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duties political parties  demand of their registered members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duties an individual imposes on himself</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Power, in the context of politics and governance, refers to the ability to influence others or impose one's will upon others. It is the capacity or ability to direct or influence the behavior of others or the course of events. None of the other options accurately define the concept of power.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prorogation is the bringing of a session of a parliament to an end through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">royal proclamation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">final reading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guillotine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">impeachment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prorogation is the formal ending of a parliamentary session and it is typically done through a royal proclamation. It is the discontinuation of a session of a parliament or other legislative assembly without dissolving it. It is not brought about by final reading, guillotine, or impeachment.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The right of all eligible citizens to vote and be voted for is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gender equality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political mandate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restricted franchise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">universal suffrage</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The right of all eligible citizens to vote and be voted for is referred to as universal suffrage. Universal suffrage means that the right to vote should not be restricted by race, sex, belief, wealth, or social status. The term is associated with the expansion of voting rights to adult citizens.</div>", "topic": "CITIZENSHIP : CITIZENSHIP RIGHTS"}, {"id": "objective>Government>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Values, beliefs, and orientation of a political system are internalized through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political culture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political socialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political power</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Values, beliefs, and orientation of a political system are internalized through political socialization. Political socialization is a lifelong process by which people form their ideas about politics and acquire political values. The family, educational system, and mass media are important socializing agents.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL PROCESSES: POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Occupational pressure groups pursue their objectives mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">issuing ultimatums and embarking on strikes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alienating the government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">embarking on guerrilla welfare</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contesting elections</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Occupational pressure groups, also known as interest groups, are organizations that seek to influence government policy, public opinion, or business decisions. They pursue their objectives mainly by issuing ultimatums and embarking on strikes. This is a common method used to exert pressure on the government or businesses to meet their demands. They do not typically alienate the government, embark on guerrilla warfare, or contest elections as these are not effective or appropriate methods for achieving their goals.</div>", "topic": "PRESSURE GROUPS"}, {"id": "objective>Government>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a cabinet system, the legislature comprises the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prime minister and members of the parliament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prime minister and member of the jury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prime minister and ministers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">president and ministers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a cabinet system of government, the legislature comprises the prime minister and members of the parliament. The prime minister is the head of government and the members of parliament are the elected representatives of the people. They work together to make laws and govern the country. The cabinet system does not include members of the jury, ministers, or the president in the legislature.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The committee that scrutinizes budget proposals in the legislature is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rules and Business Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Public Accounts Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Finance Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Appropriation Committee</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Appropriation Committee is the committee that scrutinizes budget proposals in the legislature. This committee is responsible for examining the estimates of government expenditure submitted by the Finance Minister in his budget and suggesting economies in public expenditure. The other committees listed do not have this specific function.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Democracy is a system of government that is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constituted by the will of the majority of the citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imposed on the majority of the citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">designed to favour the elite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">put in place to favour the party caucus</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Democracy is a system of government that is constituted by the will of the majority of the citizens. In a democracy, the power to govern is derived from the people, who express their will through elections. The other options do not accurately describe the nature of a democratic system.</div>", "topic": "FORMS OF GOVERNMENT : DEMOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Collective ownership of property is associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">federalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mercantilism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Collective ownership of property is a key principle of communism. In a communist society, all property is publicly owned and each person works and is paid according to their abilities and needs. This is different from federalism, mercantilism, and capitalism where property is privately owned.</div>", "topic": "POLITICAL IDEOLOGIES : COMMUNISM"}, {"id": "objective>Government>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The agency responsible for investigating allegations of maladministration in the civil service is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Federal Civil Services Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Code of Conduct Bureau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Public Complaints Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Character Commission</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Public Complaints Commission, also known as the Ombudsman, is the agency responsible for investigating allegations of maladministration in the civil service. It serves as a watchdog to ensure administrative justice in public offices. The Federal Civil Services Commission is responsible for appointment, promotion, and discipline in the civil service. The Code of Conduct Bureau is responsible for ensuring that public officers adhere to the code of conduct for public officers. The Federal Character Commission ensures fair and equitable distribution of posts and socio-economic amenities among the federating units of Nigeria.</div>", "topic": "PUBLIC COMMISSIONS ESTABLISHED BY THE 1979 AND SUBSEQUENT CONSTITUTIONS : THE PUBLIC COMPLAINTS COMMISSION"}, {"id": "objective>Government>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A political entity that possesses independence is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">state</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A political entity that possesses independence is a state. A state is a political entity that possesses a permanent population, a defined territory, a government, and the capacity to enter into relations with other states. It is independent because it has sovereignty, which means it has supreme power or authority over its territory and is not controlled by an outside force.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principles that advocates strict adherence to the fundamental laws of a country is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constitutionalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absolutism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collective responsibility</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle that advocates strict adherence to the fundamental laws of a country is constitutionalism. Constitutionalism is a political philosophy that asserts that governance should be conducted according to an established set of laws, such as a constitution. It is the idea that government should be limited in its powers and that its authority depends on its observation of these laws.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : CONSTITUTIONALISM, RULE OF LAW AND REPRESENTATIVE GOVERNMENT"}, {"id": "objective>Government>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One advantage of the unitary systems over federal system is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bureaucratic nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost effectiveness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small membership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ratification of appointments</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A unitary system of government is a sovereign state governed as a single entity. The central government is supreme, and the administrative divisions exercise only powers that the central government has delegated to them. This makes it more cost-effective as it avoids duplication of government functions in multiple levels of government, unlike in a federal system where there is a division of powers between the central government and the constituent units.</div>", "topic": "STRUCTURES OF GOVERNANCE : UNITARY FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a duty of an electoral commission?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Registration of political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Creation of political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Establishment of electoral tribunals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inauguration of the parliament</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An electoral commission is a body responsible for administering elections. One of its key duties is the registration of political parties. It does not create political parties, establish electoral tribunals, or inaugurate the parliament. These are functions of other arms of government.</div>", "topic": "THE ELECTORAL PROCESS : ELECTORAL COMMISSION – FUNCTIONS, PROBLEMS."}, {"id": "objective>Government>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A form of government in which the nobles rule for the benefit of all is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gerontocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aristocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plutocracy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aristocracy is a form of government in which power is in the hands of a small, privileged, ruling class, the nobles. The nobles rule with the understanding that they are to use their power and influence for the benefit of all citizens, not just their own class.</div>", "topic": "FORMS OF GOVERNMENT : ARISTOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fascism as an ideology facilitates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">totalitarianism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberalism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fascism is a political ideology that is marked by dictatorial power, forcible suppression of opposition, and strong regimentation of society and of the economy which is also known as totalitarianism. Therefore, fascism facilitates totalitarianism.</div>", "topic": "POLITICAL IDEOLOGIES : FASCISM"}, {"id": "objective>Government>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A prominent feature of a presidential system of government is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dual executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vote of no confidence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rule of law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">separation of powers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A prominent feature of a presidential system of government is the 'separation of powers'. This means that the executive, legislative, and judicial branches of government are distinct, with each having its own responsibilities. This system prevents any one branch from gaining too much power and ensures a balance of power.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The executive checks the excesses of the legislature through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assent to bills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of veto powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ratification of treaties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issuance of orders</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The executive checks the excesses of the legislature through 'the use of veto powers'. The veto power allows the executive (the president or governor, for example) to refuse to sign a bill into law. This is a key check and balance in a democratic system, as it prevents the legislature from passing laws without the agreement of the executive.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The consciousness of a common identity of  a people is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nationalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indoctrination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emancipation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consciousness of a common identity of a people is called nationalism. Nationalism is a political ideology that involves a strong identification of a group of individuals with a political entity defined in national terms, i.e. a nation. It is the sense of a common identity, including language, culture, and shared experiences, among a nation's people.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Citizenship of a state by descent requires that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">one is born and bred in the state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one's mother was born in the state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one's grandparents were citizens of the state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one is domiciled in that state</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Citizenship of a state by descent requires that one's grandparents were citizens of the state. This is known as jus sanguinis, or right of blood, which is a principle of nationality law by which citizenship is determined or acquired by the nationality or ethnicity of one or both parents. This means that you are considered a citizen of a country if your parents or grandparents were citizens, regardless of where you were born.</div>", "topic": "CITIZENSHIP : MEANING AND TYPES"}, {"id": "objective>Government>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to dispense justice impartially, the judiciary primarily needs</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discipline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">logistics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The judiciary needs independence primarily to dispense justice impartially. Independence ensures that the judiciary is not influenced by external forces such as the executive or legislative branches of government, or by personal interests. This allows the judiciary to make decisions based solely on the law and the facts of each case, ensuring fair and impartial justice.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A state with a hegemonic political party is one in which </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is one dominant party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no opposition party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is only one party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">other parties are officially recognized</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A state with a hegemonic political party is one in which there is one dominant party. This does not necessarily mean that there are no other parties, but rather that one party has overwhelming influence or control over the political landscape. This dominance could be due to a variety of factors, such as popular support, control of resources, or institutional advantages.</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS – DEFINITION, ORGANIZATION, FUNCTIONS."}, {"id": "objective>Government>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's committment to the liberation of Africa could best be seen in her policy towards</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Namibia and Mozanbique</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Congo and Zimbabwu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sierra leone and Chad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa and Angola</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's commitment to the liberation of Africa was most evident in her policy towards South Africa and Angola. During the apartheid era, Nigeria was one of the foremost supporters of anti-apartheid movements, including the African National Congress. The country also provided substantial support to the Popular Movement for the Liberation of Angola (MPLA), which was fighting for independence from Portugal. This support was in line with Nigeria's foreign policy, which was heavily focused on decolonization and anti-apartheid efforts in Africa.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE AFRICAN UNION"}, {"id": "objective>Government>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The set of policies on the basis of which countries interact with one another is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constructive engagement policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socio-economic policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign policy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Foreign policy refers to the set of policies on the basis of which countries interact with one another. It involves making choices about relations with other countries. Foreign policy includes diplomacy, security, international trade policies, and humanitarian efforts. It is designed by the government to achieve complex domestic and international goals. It protects the national interest, national security, ideological goals, and economic prosperity. The other options do not accurately describe the set of policies that guide international relations.</div>", "topic": "FOREIGN POLICY : DEFINITION AND PURPOSE"}, {"id": "objective>Government>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian membership of the UN complements her foreign policy in the area of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bilateral diplomacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regional diplomacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sub-regional diplomacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multilateral diplomacy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's membership of the United Nations (UN) complements her foreign policy in the area of multilateral diplomacy. Multilateral diplomacy refers to the practice of involving more than two nations or parties in achieving diplomatic solutions to international challenges. The UN is a global organization that facilitates multilateral diplomacy by providing a platform for dialogue and negotiation among its member states.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS"}, {"id": "objective>Government>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian teamed up with other developing countries to assert a neutral posture under the platform of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nationalist Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pan-African Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Non-aligned Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Negritude movement</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria teamed up with other developing countries to assert a neutral posture under the platform of the Non-aligned Movement. The Non-aligned Movement was a group of states which were not formally aligned with or against any major power bloc during the Cold War. It provided a platform for countries to ensure their independent policy stance, free from the influence of major powers.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}];
